# v6.19 Professional Consolidation Layer (Oil 15M)
# ==========================================================

PRIMARY_EXECUTION_SETUPS = {
    "OB_RECLAIM",
    "ACCEPTANCE_RETEST_CONTINUATION",
    "LIQUIDITY_RECOVERY",
}

CONTEXT_ONLY_SETUPS = {
    "SILVER_BULLET",
    "JUDAS_SWING",
    "OPENING_RANGE_BREAKOUT",
    "SESSION_MEAN_RECLAIM",
    "FAILED_AUCTION_REJECTION",
    "DAILY_WEEKLY_OPEN_RECLAIM",
}


def setup_role(setup_type: str) -> str:
    """Single hierarchy for setup influence."""
    name = str(setup_type or "").upper()
    if name in PRIMARY_EXECUTION_SETUPS:
        return "PRIMARY_EXECUTION"
    if name in CONTEXT_ONLY_SETUPS:
        return "CONTEXT"
    return "SUPPORT"



def calculate_unified_risk_adjustment(candidate: Any) -> dict[str, Any]:
    """Deprecated compatibility view of the canonical risk ledger."""
    ledger = build_risk_adjustment_ledger(candidate, {}, stage=getattr(candidate, "entry_stage", "WATCH"))
    return {
        "multipliers": {a.source: a.factor for a in ledger.adjustments if a.applied},
        "combined": ledger.combined_confidence_multiplier,
        "ledger": asdict(ledger),
        "deprecated": True,
    }

def scoring_mode_profile(status: Optional[dict[str, Any]]) -> dict[str, Any]:
    status = status or {}
    ready = bool(status.get("global_ready"))
    weight = safe_float(status.get("global_learned_weight"), 0.0)
    rows = int(status.get("training_rows", 0) or 0)
    if not ready or weight <= 0.0:
        code = "NOT_LEARNED"
        label = "NOT LEARNED — евристичні ваги"
    elif weight < 0.50:
        code = "LEARNING_BLEND"
        label = "PARTIALLY LEARNED — bootstrap + learned blend"
    else:
        code = "LEARNED_BLEND"
        label = "LEARNED BLEND"
    return {
        "code": code,
        "label": label,
        "global_ready": ready,
        "learned_weight": round(weight, 4),
        "training_rows": rows,
        "minimum_rows": SCORING_MODEL_MIN_TRADES,
        "quality_is_empirically_calibrated": bool(ready and weight > 0.0),
    }


def _signal_quality_dimensions(signal: dict[str, Any]) -> dict[str, int]:
    components = signal.get("score_components") or {}
    dimensions = signal.get("quality_dimensions") or {}
    return {
        "entry_quality": int(safe_float(
            signal.get("entry_score", dimensions.get("entry_quality", components.get("entry_quality", signal.get("score", signal.get("quality", 0))))), 0
        )),
        "durability_quality": int(safe_float(
            signal.get("durability_score", dimensions.get("durability_quality", components.get("durability_quality", components.get("exit_quality", 0)))), 0
        )),
    }


def _signal_execution_path(signal: Optional[dict[str, Any]]) -> dict[str, Any]:
    signal = signal or {}
    compact_category = str(signal.get("execution_path") or "")
    if compact_category in {"STANDARD", "REVALIDATION", "INNOVATION_FALLBACK"}:
        entry_supported = bool(signal.get("entry_supported", True))
        executable = str(signal.get("action") or "") in EXECUTABLE_ENTRY_ACTIONS
        return {
            "category": compact_category,
            "fallback": compact_category in {"REVALIDATION", "INNOVATION_FALLBACK"},
            "standard": compact_category == "STANDARD",
            "primary": compact_category,
            "revalidation_state": "COMPACT_V2",
            "entry_supported": entry_supported,
            "unsupported_execution": bool(executable and not entry_supported),
        }
    revalidation = signal.get("trigger_revalidation") or (signal.get("score_components") or {}).get("trigger_revalidation") or {}
    innovation = signal.get("innovation_profile") or (signal.get("score_components") or {}).get("innovation_profile") or {}
    primary = str(innovation.get("primary") or "")
    revalidated = bool(revalidation.get("revalidated"))
    entry_supported = bool(revalidation.get("entry_supported", True))
    action = str(signal.get("action") or "")
    executable = action in EXECUTABLE_ENTRY_ACTIONS

    if revalidated or primary == "SETUP_ARGUMENTED_TRIGGER_REVALIDATION":
        category = "REVALIDATION"
    elif primary and primary != "STANDARD_NONBLOCKING_CONSTRUCTION":
        category = "INNOVATION_FALLBACK"
    else:
        category = "STANDARD"

    unsupported_execution = bool(executable and not entry_supported)
    return {
        "category": category,
        "fallback": category in {"REVALIDATION", "INNOVATION_FALLBACK"},
        "standard": category == "STANDARD",
        "primary": primary or "UNRECORDED",
        "revalidation_state": str(revalidation.get("state") or ""),
        "entry_supported": entry_supported,
        "unsupported_execution": unsupported_execution,
    }


def compute_execution_path_health(journal: dict[str, Any]) -> dict[str, Any]:
    signals = {
        str(s.get("id")): s
        for s in journal.get("signals", []) or []
        if isinstance(s, dict) and s.get("id")
    }
    counts = {"STANDARD": 0, "REVALIDATION": 0, "INNOVATION_FALLBACK": 0, "UNKNOWN": 0}
    unsupported: list[dict[str, Any]] = []
    by_setup: dict[str, dict[str, int]] = {}

    trades = [t for t in journal.get("trades", []) or [] if isinstance(t, dict)]
    for trade in trades:
        signal = signals.get(str(trade.get("signal_id") or ""))
        if signal:
            profile = _signal_execution_path(signal)
            category = profile["category"]
        else:
            category = "UNKNOWN"
            profile = {"unsupported_execution": False, "primary": "MISSING_SIGNAL", "entry_supported": False}
        counts[category] = counts.get(category, 0) + 1
        setup = str(trade.get("setup_type") or "UNKNOWN")
        row = by_setup.setdefault(setup, {"total": 0, "standard": 0, "fallback": 0})
        row["total"] += 1
        if category == "STANDARD":
            row["standard"] += 1
        elif category in {"REVALIDATION", "INNOVATION_FALLBACK"}:
            row["fallback"] += 1
        if profile.get("unsupported_execution"):
            unsupported.append({
                "trade_id": trade.get("id"),
                "signal_id": trade.get("signal_id"),
                "setup_type": setup,
                "innovation_primary": profile.get("primary"),
            })

    total = len(trades)
    fallback_count = counts.get("REVALIDATION", 0) + counts.get("INNOVATION_FALLBACK", 0)
    fallback_pct = round(100.0 * fallback_count / total, 2) if total else 0.0
    standard_pct = round(100.0 * counts.get("STANDARD", 0) / total, 2) if total else 0.0
    if unsupported:
        health = "CRITICAL"
        reason = "executable trade detected while entry_supported=false"
    elif total and fallback_pct >= 100.0:
        health = "CRITICAL"
        reason = "all closed trades depend on revalidation/innovation"
    elif total and fallback_pct >= 75.0:
        health = "CAUTION"
        reason = "revalidation/innovation dominates closed trades"
    else:
        health = "OK" if total else "NO_DATA"
        reason = "execution paths are diversified" if total else "no closed trades"

    return {
        "closed_trades": total,
        "counts": counts,
        "standard_pct": standard_pct,
        "revalidation_or_innovation_pct": fallback_pct,
        "unsupported_execution_count": len(unsupported),
        "unsupported_executions": unsupported[-20:],
        "by_setup_type": by_setup,
        "health": health,
        "reason": reason,
        "definition": "closed trades joined to originating signal_id; fallback = REVALIDATION or non-standard INNOVATION primary",
        "updated_at": iso_now(),
    }


def _clean_setup_reason(signal: dict[str, Any]) -> str:
    if signal.get("blocking_reason"):
        return str(signal.get("blocking_reason"))[:120]
    if bool(signal.get("confirmation_pending")):
        return "CONFIRMATION_PENDING"
    revalidation = signal.get("trigger_revalidation") or {}
    if not bool(revalidation.get("entry_supported", True)):
        return "REVALIDATION_NOT_SUPPORTED"
    lane = str(signal.get("execution_lane") or "")
    if lane in {ExecutionLane.WAIT_RETEST.value, ExecutionLane.WAIT_CONFIRMATION.value, ExecutionLane.LIMIT_ONLY.value}:
        return lane
    rejected = ((signal.get("audit") or {}).get("rejected_hypotheses") or [])
    if rejected:
        return str((rejected[0] or {}).get("failed_gate") or "REJECTED_HYPOTHESIS")[:120]
    return str(signal.get("reason") or signal.get("action") or "UNKNOWN")[:120]



def compute_execution_conversion_funnel(journal: dict[str, Any]) -> dict[str, Any]:
    target_types = {
        SetupType.ACCEPTANCE_RETEST_CONTINUATION.value,
        SetupType.MOMENTUM_NO_PULLBACK_CONTINUATION.value,
    }
    stage_names = [
        "detected", "score_eligible", "trigger_ready", "entry_supported",
        "plan_execution_ready", "philosophy_accepts", "executive_pre_conflict_eligible",
        "entry_published",
    ]
    by_setup: dict[str, Any] = {}
    blocker_totals: dict[str, int] = {}
    for setup_type in sorted(target_types):
        records = [s for s in journal.get("signals", []) or [] if isinstance(s, dict) and str(s.get("setup_type") or "") == setup_type]
        counts = {name: 0 for name in stage_names}
        thesis_sets = {name: set() for name in stage_names}
        blockers: dict[str, int] = {}
        blocker_theses: dict[str, set[str]] = {}
        for signal in records:
            funnel = ((signal.get("audit") or {}).get("execution_funnel") or signal.get("execution_funnel") or signal.get("funnel") or {})
            thesis = str(signal.get("thesis_key") or signal.get("id") or "")
            revalidation = _signal_revalidation_profile(signal)
            inferred = {
                "detected": True,
                "score_eligible": int(signal.get("score", signal.get("candidate_final_score", signal.get("quality", 0))) or 0) >= RISKY_ENTRY_SCORE_BASE,
                "trigger_ready": bool(signal.get("trigger_ready")),
                "entry_supported": bool(revalidation.get("entry_supported", True)),
                "plan_execution_ready": bool(funnel.get("plan_execution_ready", str(signal.get("action") or "") in EXECUTABLE_ENTRY_ACTIONS)),
                "philosophy_accepts": bool(funnel.get("philosophy_accepts", False)),
                "executive_pre_conflict_eligible": bool(funnel.get("executive_pre_conflict_eligible", False)),
                "entry_published": str(signal.get("action") or "") in EXECUTABLE_ENTRY_ACTIONS,
            }
            chain_open = True
            for name in stage_names:
                raw_passed = bool(funnel.get(name, inferred[name]))
                chain_open = bool(chain_open and raw_passed)
                if chain_open:
                    counts[name] += 1
                    if thesis:
                        thesis_sets[name].add(thesis)
            blocker = str(
                funnel.get("blocking_layer")
                or ("REVALIDATION" if not inferred["entry_supported"] else "LEGACY_UNATTRIBUTED_AFTER_ENTRY_SUPPORTED")
            )
            if blocker != "NONE":
                blockers[blocker] = blockers.get(blocker, 0) + 1
                blocker_totals[blocker] = blocker_totals.get(blocker, 0) + 1
                if thesis:
                    blocker_theses.setdefault(blocker, set()).add(thesis)
        transitions = []
        for previous, current in zip(stage_names, stage_names[1:]):
            base = counts[previous]
            transitions.append({
                "from": previous, "to": current,
                "from_count": base, "to_count": counts[current],
                "conversion_pct": round(100.0 * counts[current] / base, 2) if base else 0.0,
            })
        by_setup[setup_type] = {
            "scan_counts": counts,
            "unique_thesis_counts": {name: len(values) for name, values in thesis_sets.items()},
            "transitions": transitions,
            "blocking_layers": blockers,
            "blocking_layers_unique_theses": {name: len(values) for name, values in blocker_theses.items()},
            "revalidation_blocked": blockers.get("REVALIDATION", 0),
            "revalidation_blocked_unique_theses": len(blocker_theses.get("REVALIDATION", set())),
            "executive_director_blocked": blockers.get("EXECUTIVE_DIRECTOR_CONFLICT", 0) + blockers.get("EXECUTIVE_DIRECTOR_POLICY", 0),
        }
    return {
        "by_setup": by_setup,
        "blocking_layers_total": blocker_totals,
        "definition": "scan-level and unique-thesis funnel; REVALIDATION is measured before Executive Director",
        "updated_at": iso_now(),
    }

def compute_clean_setup_conversion(journal: dict[str, Any]) -> dict[str, Any]:
    target_types = {
        SetupType.ACCEPTANCE_RETEST_CONTINUATION.value,
        SetupType.MOMENTUM_NO_PULLBACK_CONTINUATION.value,
    }
    result: dict[str, Any] = {}
    for setup_type in sorted(target_types):
        records = [
            s for s in journal.get("signals", []) or []
            if isinstance(s, dict) and str(s.get("setup_type") or "") == setup_type
        ]
        unique_theses = {str(s.get("thesis_key") or s.get("id") or "") for s in records}
        entries = [s for s in records if str(s.get("action") or "") in EXECUTABLE_ENTRY_ACTIONS]
        direct = [s for s in entries if _signal_execution_path(s).get("standard")]
        fallback = [s for s in entries if _signal_execution_path(s).get("fallback")]
        reasons: dict[str, int] = {}
        reason_theses: dict[str, set[str]] = {}
        for signal in records:
            if str(signal.get("action") or "") in EXECUTABLE_ENTRY_ACTIONS:
                continue
            reason = _clean_setup_reason(signal)
            reasons[reason] = reasons.get(reason, 0) + 1
            thesis = str(signal.get("thesis_key") or signal.get("id") or "")
            if thesis:
                reason_theses.setdefault(reason, set()).add(thesis)
        result[setup_type] = {
            "scan_records": len(records),
            "unique_theses": len({x for x in unique_theses if x}),
            "entry_signals": len(entries),
            "direct_standard_entries": len(direct),
            "revalidation_or_innovation_entries": len(fallback),
            "direct_conversion_pct_of_entries": round(100.0 * len(direct) / len(entries), 2) if entries else 0.0,
            "fallback_dependency_pct_of_entries": round(100.0 * len(fallback) / len(entries), 2) if entries else 0.0,
            "top_non_conversion_reasons": [
                {"reason": reason, "count": count}
                for reason, count in sorted(reasons.items(), key=lambda item: (-item[1], item[0]))[:8]
            ],
            "top_non_conversion_reasons_unique_theses": [
                {"reason": reason, "unique_theses": len(values)}
                for reason, values in sorted(reason_theses.items(), key=lambda item: (-len(item[1]), item[0]))[:8]
            ],
        }
    return {
        "setups": result,
        "definition": "scan-level plus unique-thesis conversion audit; direct = STANDARD path, fallback = REVALIDATION/INNOVATION",
        "updated_at": iso_now(),
    }


def _pearson_correlation(xs: list[float], ys: list[float]) -> Optional[float]:
    if len(xs) != len(ys) or len(xs) < 3:
        return None
    mx, my = mean(xs), mean(ys)
    numerator = sum((x - mx) * (y - my) for x, y in zip(xs, ys))
    dx = math.sqrt(sum((x - mx) ** 2 for x in xs))
    dy = math.sqrt(sum((y - my) ** 2 for y in ys))
    if dx <= 1e-12 or dy <= 1e-12:
        return None
    return numerator / (dx * dy)


def _average_ranks(values: list[float]) -> list[float]:
    indexed = sorted(enumerate(values), key=lambda item: item[1])
    ranks = [0.0] * len(values)
    i = 0
    while i < len(indexed):
        j = i
        while j + 1 < len(indexed) and indexed[j + 1][1] == indexed[i][1]:
            j += 1
        rank = (i + j + 2) / 2.0
        for k in range(i, j + 1):
            ranks[indexed[k][0]] = rank
        i = j + 1
    return ranks


def compute_score_outcome_correlation(journal: dict[str, Any], enabled: bool) -> dict[str, Any]:
    signals = {
        str(s.get("id")): s
        for s in journal.get("signals", []) or []
        if isinstance(s, dict) and s.get("id")
    }
    rows: list[dict[str, float]] = []
    for trade in journal.get("trades", []) or []:
        if not isinstance(trade, dict):
            continue
        signal = signals.get(str(trade.get("signal_id") or ""))
        if not signal:
            continue
        dims = _signal_quality_dimensions(signal)
        realized_return_pct = _journal_realized_return_pct(trade)
        if realized_return_pct is None:
            continue
        rows.append({
            "score": safe_float(signal.get("score", signal.get("candidate_final_score", signal.get("quality"))), 0.0),
            "entry_quality": safe_float(dims.get("entry_quality"), 0.0),
            "durability_quality": safe_float(dims.get("durability_quality"), 0.0),
            "result_pct": realized_return_pct,
            "mfe_pct": safe_float(trade.get("mfe_pct", trade.get("mfe")), 0.0),
        })

    if not enabled:
        return {
            "enabled": False,
            "reason": "global_not_ready",
            "samples": len(rows),
            "minimum_samples": SCORING_MODEL_MIN_TRADES,
        }
    if len(rows) < 3:
        return {"enabled": False, "reason": "too_few_joined_rows", "samples": len(rows)}

    result_values = [row["result_pct"] for row in rows]
    mfe_values = [row["mfe_pct"] for row in rows]

    def corr(field: str, target: list[float]) -> dict[str, Any]:
        source = [row[field] for row in rows]
        pearson = _pearson_correlation(source, target)
        spearman = _pearson_correlation(_average_ranks(source), _average_ranks(target))
        return {
            "pearson": round(pearson, 4) if pearson is not None else None,
            "spearman": round(spearman, 4) if spearman is not None else None,
        }

    return {
        "enabled": True,
        "samples": len(rows),
        "final_score_vs_result_pct": corr("score", result_values),
        "entry_quality_vs_mfe_pct": corr("entry_quality", mfe_values),
        "durability_quality_vs_result_pct": corr("durability_quality", result_values),
        "note": "correlation is descriptive, not causal; review confidence intervals before changing thresholds",
    }


def compute_setup_statistics(journal: dict[str, Any]) -> dict[str, Any]:
    """Performance memory by setup type and family.

    Both keys are emitted so callers can evaluate a precise setup_type or the
    broader setup_family without inventing a second statistics pipeline.
    """
    stats: dict[str, dict[str, Any]] = {}
    signals = {
        str(s.get("id")): s
        for s in journal.get("signals", []) or []
        if isinstance(s, dict) and s.get("id")
    }

    def _record(key: str, result_r: float, path_category: str = "UNKNOWN") -> None:
        if not key:
            return
        bucket = stats.setdefault(
            key,
            {
                "trades": 0, "closed_trades": 0, "wins": 0, "net_r": 0.0,
                "standard_path": 0, "revalidation_or_innovation_path": 0, "unknown_path": 0,
            },
        )
        bucket["trades"] += 1
        bucket["closed_trades"] += 1
        bucket["net_r"] += result_r
        if result_r > 0:
            bucket["wins"] += 1
        if path_category == "STANDARD":
            bucket["standard_path"] += 1
        elif path_category in {"REVALIDATION", "INNOVATION_FALLBACK"}:
            bucket["revalidation_or_innovation_path"] += 1
        else:
            bucket["unknown_path"] += 1

    for trade in journal.get("trades", []):
        if not isinstance(trade, dict):
            continue
        result = _journal_result_r(trade)
        if result is None:
            continue
        setup_type = str(trade.get("setup_type", "UNKNOWN") or "UNKNOWN")
        setup_family = str(trade.get("setup_family", "") or "")
        signal = signals.get(str(trade.get("signal_id") or ""))
        path_category = _signal_execution_path(signal).get("category", "UNKNOWN") if signal else "UNKNOWN"
        _record(setup_type, result, path_category)
        if setup_family and setup_family != setup_type:
            _record(setup_family, result, path_category)

    for bucket in stats.values():
        closed = int(bucket.get("closed_trades", 0) or 0)
        bucket["net_r"] = round(float(bucket.get("net_r", 0.0) or 0.0), 4)
        bucket["win_rate"] = round(bucket["wins"] / closed * 100, 2) if closed else 0.0
        bucket["expectancy_r"] = round(bucket["net_r"] / closed, 4) if closed else 0.0
        bucket["standard_path_pct"] = round(bucket["standard_path"] / closed * 100, 2) if closed else 0.0
        bucket["fallback_path_pct"] = round(bucket["revalidation_or_innovation_path"] / closed * 100, 2) if closed else 0.0

    return stats



def _wilson_interval(wins: int, total: int, z: float = WEEKEND_RANGE_WILSON_Z) -> tuple[float, float]:
    """Wilson score interval for a binomial win rate, returned in [0, 1]."""
    if total <= 0:
        return 0.0, 1.0
    p = wins / total
    denom = 1.0 + (z * z / total)
    centre = (p + (z * z / (2.0 * total))) / denom
    margin = (z / denom) * math.sqrt((p * (1.0 - p) / total) + (z * z / (4.0 * total * total)))
    return max(0.0, centre - margin), min(1.0, centre + margin)


def compute_calendar_statistics(journal: dict[str, Any]) -> dict[str, Any]:
    """Compare RANGE trades opened on weekends versus weekdays.

    This is deliberately observational. It does not mutate Regime.RANGE or its
    thresholds. A split is merely marked as statistically supported after both
    buckets have enough samples and 95% Wilson win-rate intervals do not overlap.
    """
    buckets = {
        "weekend": {"closed_trades": 0, "wins": 0, "net_result": 0.0},
        "weekday": {"closed_trades": 0, "wins": 0, "net_result": 0.0},
    }
    for trade in journal.get("trades", []) or []:
        if not isinstance(trade, dict) or str(trade.get("opened_regime") or "") != Regime.RANGE.value:
            continue
        opened = _parse_iso_datetime(trade.get("opened_at", trade.get("time")))
        if opened is None:
            continue
        key = "weekend" if opened.weekday() >= 5 else "weekday"
        result = _journal_result_r(trade)
        if result is None:
            continue
        bucket = buckets[key]
        bucket["closed_trades"] += 1
        bucket["wins"] += 1 if result > 0 else 0
        bucket["net_result"] += result

    for bucket in buckets.values():
        total = int(bucket["closed_trades"])
        wins = int(bucket["wins"])
        lo, hi = _wilson_interval(wins, total)
        bucket["win_rate_pct"] = round((wins / total * 100.0) if total else 0.0, 2)
        bucket["expectancy"] = round((bucket["net_result"] / total) if total else 0.0, 4)
        bucket["net_result"] = round(bucket["net_result"], 4)
        bucket["win_rate_wilson_95"] = [round(lo * 100.0, 2), round(hi * 100.0, 2)]

    weekend = buckets["weekend"]
    weekday = buckets["weekday"]
    enough = (
        weekend["closed_trades"] >= WEEKEND_RANGE_MIN_TRADES_PER_BUCKET
        and weekday["closed_trades"] >= WEEKEND_RANGE_MIN_TRADES_PER_BUCKET
    )
    w_lo, w_hi = [x / 100.0 for x in weekend["win_rate_wilson_95"]]
    d_lo, d_hi = [x / 100.0 for x in weekday["win_rate_wilson_95"]]
    intervals_separate = bool(w_hi < d_lo or d_hi < w_lo)
    split_supported = bool(enough and intervals_separate)
    return {
        "range_weekend_vs_weekday": {
            "weekend": weekend,
            "weekday": weekday,
            "minimum_trades_per_bucket": WEEKEND_RANGE_MIN_TRADES_PER_BUCKET,
            "enough_samples": enough,
            "wilson_intervals_separate": intervals_separate,
            "split_supported": split_supported,
            "decision": "SPLIT_SUPPORTED" if split_supported else "KEEP_SHARED_RANGE",
            "reason": (
                "statistically distinct RANGE win rates"
                if split_supported
                else "insufficient evidence for a separate weekend regime"
            ),
        }
    }

def _parse_iso_datetime(value: Any) -> Optional[datetime]:
    if not value:
        return None
    try:
        parsed = datetime.fromisoformat(str(value).replace("Z", "+00:00"))
        if parsed.tzinfo is None:
            parsed = parsed.replace(tzinfo=timezone.utc)
        return parsed.astimezone(timezone.utc)
    except (TypeError, ValueError):
        return None


def compute_daily_risk_used(journal: dict[str, Any], at: Optional[datetime] = None) -> float:
    """Return risk already consumed by trades closed on the UTC trading day.

    Open exposure is intentionally excluded and is handled separately by
    compute_open_position_risk(), preventing the same trade from being counted
    twice. Legacy trade rows without a timestamp cannot be assigned to a day
    safely and are therefore ignored rather than guessed.
    """
    day = (at or now_utc()).astimezone(timezone.utc).date()
    total = 0.0
    seen: set[tuple[str, str]] = set()

    for trade in journal.get("trades", []) or []:
        if not isinstance(trade, dict):
            continue
        closed_at = _parse_iso_datetime(trade.get("closed_at"))
        if closed_at is None or closed_at.date() != day:
            continue
        key = (str(trade.get("id") or ""), str(trade.get("signal_id") or ""))
        if key != ("", "") and key in seen:
            continue
        seen.add(key)
        total += max(0.0, safe_float(trade.get("position_risk_pct", trade.get("risk_pct")), 0.0))

    return round(total, 4)


def compute_open_position_risk(state: dict[str, Any]) -> float:
    """Return current open risk in the same percentage-point units as the cap."""
    raw = (state or {}).get("active_trade")
    if not isinstance(raw, dict):
        return 0.0
    if str(raw.get("status", "OPEN")).upper() == "CLOSED":
        return 0.0
    return round(max(0.0, safe_float(raw.get("position_risk_pct"), 0.0)), 4)

def atomic_json_write(path: Path, data: dict[str, Any]) -> None:
    path.parent.mkdir(parents=True, exist_ok=True)
    temp = path.with_suffix(path.suffix + ".tmp")
    backup = path.with_suffix(path.suffix + ".bak")
    payload = json_safe(data)
    with temp.open("w", encoding="utf-8") as fh:
        json.dump(payload, fh, ensure_ascii=False, separators=(",", ":"))
    os.replace(temp, path)
    with backup.open("w", encoding="utf-8") as fh:
        json.dump(payload, fh, ensure_ascii=False, separators=(",", ":"))


def load_json(path: Path, default: dict[str, Any]) -> dict[str, Any]:
    try:
        if not path.exists():
            return default
        with path.open("r", encoding="utf-8") as fh:
            value = json.load(fh)
        return value if isinstance(value, dict) else default
    except Exception as exc:
        print(f"[WARN] JSON read failed {path}: {exc}")
        return default


def load_state() -> dict[str, Any]:
    raw = load_json(STATE_FILE, {})
    # v8.10 changes execution support semantics, not the serialized state shape.
    # Preserve v8.8/v8.9 Opportunity (especially CONFIRMATION_PENDING), scan_3m
    # and regime memory instead of silently discarding the bar we are waiting for.
    compatible_architectures = {
        ARCHITECTURE_VERSION,
        "TRADING_DESK_EXECUTIVE_V9_5_6_PRECONFIRMATION_CONTRACT_GUARD",
        "TRADING_DESK_EXECUTIVE_V9_5_3_JOURNAL_COMPACTION",
        "TRADING_DESK_EXECUTIVE_V9_5_2_MODEL_LOCAL_THESIS_LADDER_CONFIRMATION",
        "TRADING_DESK_EXECUTIVE_V9_5_1_TTL_BRIDGE_SYNCED_EARLY_PRECONFIRM",
        "TRADING_DESK_EXECUTIVE_V9_4_CONFIRMATION_PROBABILITY",
        "TRADING_DESK_EXECUTIVE_V9_3_RISK_INTEGRITY",
        "TRADING_DESK_EXECUTIVE_V8_10_REVALIDATION_PATHS",
        "TRADING_DESK_EXECUTIVE_V8_9_DIRECTION_AWARE",
        "TRADING_DESK_EXECUTIVE_V8_8_CONFIDENCE_AWARE",
    }
    same_arch = raw.get("architecture_version") in compatible_architectures
    return {
        "version": BOT_VERSION,
        "architecture_version": ARCHITECTURE_VERSION,
        "active_trade": raw.get("active_trade"),
        "opportunity": raw.get("opportunity") if same_arch else None,
        "scan_3m": _normalize_scan3m_state(raw.get("scan_3m")) if same_arch else _empty_scan3m_state(),
        "regime_memory": raw.get("regime_memory", {}) if same_arch and isinstance(raw.get("regime_memory"), dict) else {},
        "stage_history": (
            list(raw.get("stage_history") or [])[-300:]
            if same_arch
            else []
        ),
        "latest_signal": raw.get("latest_signal"),
        "last_message_key": raw.get("last_message_key", "") if same_arch else "",
        "history": list(raw.get("history") or [])[-MAX_HISTORY:],
    }


def save_state(state: dict[str, Any]) -> None:
    state["updated_at"] = iso_now()
    state["history"] = list(state.get("history") or [])[-MAX_HISTORY:]
    atomic_json_write(STATE_FILE, state)


def _journal_feature_map(payload: dict[str, Any]) -> dict[str, Any]:
    if not isinstance(payload, dict):
        return {}
    sources = [
        payload.get("features"),
        payload.get("score_features"),
        (payload.get("score_components") or {}).get("features") if isinstance(payload.get("score_components"), dict) else None,
    ]
    raw = next((source for source in sources if isinstance(source, dict) and source), {})
    if not raw:
        return {}
    return {key: raw.get(key, 0.0) for key in JOURNAL_ML_FEATURE_KEYS}


def lean_training_signal(payload: dict[str, Any]) -> dict[str, Any]:
    """Return one lean ML row with only the approved feature vector."""
    if not isinstance(payload, dict):
        return {}
    signal_id = str(payload.get("id") or payload.get("signal_id") or "").strip()
    features = _journal_feature_map(payload)
    if not signal_id or not features:
        return {}
    return {
        "id": signal_id,
        "time": payload.get("time"),
        "side": payload.get("side"),
        "setup_family": payload.get("setup_family"),
        "setup_type": payload.get("setup_type"),
        "features": features,
    }


def compact_signal_for_journal(payload: dict[str, Any]) -> dict[str, Any]:
    """Compact a signal without touching live decision logic.

    Runtime consumers receive the full payload before this function is called.
    Persistence keeps only identifiers, execution state and tiny analytics flags;
    the ML vector lives once in training_signals.
    """
    if not isinstance(payload, dict):
        return {}
    revalidation = payload.get("trigger_revalidation") or (payload.get("score_components") or {}).get("trigger_revalidation") or {}
    innovation = payload.get("innovation_profile") or (payload.get("score_components") or {}).get("innovation_profile") or {}
    funnel = ((payload.get("audit") or {}).get("execution_funnel") or payload.get("execution_funnel") or {})
    action = str(payload.get("action") or "")
    primary = str(innovation.get("primary") or "")
    existing_path = str(payload.get("execution_path") or "")
    if existing_path in {"STANDARD", "REVALIDATION", "INNOVATION_FALLBACK"}:
        execution_path = existing_path
    elif bool(revalidation.get("revalidated")) or primary == "SETUP_ARGUMENTED_TRIGGER_REVALIDATION":
        execution_path = "REVALIDATION"
    elif primary and primary != "STANDARD_NONBLOCKING_CONSTRUCTION":
        execution_path = "INNOVATION_FALLBACK"
    else:
        execution_path = "STANDARD"
    entry_supported = bool(payload.get("entry_supported", revalidation.get("entry_supported", True)))
    blocking_reason = str(
        payload.get("blocking_reason")
        or funnel.get("blocking_layer")
        or ("REVALIDATION_NOT_SUPPORTED" if not entry_supported else payload.get("reason") or action or "UNKNOWN")
    )[:120]
    compact = {
        "id": payload.get("id"),
        "time": payload.get("time"),
        "action": action,
        "side": payload.get("side"),
        "setup_family": payload.get("setup_family"),
        "setup_type": payload.get("setup_type"),
        "score": payload.get("candidate_final_score", payload.get("quality", payload.get("score"))),
        "entry_score": (
            payload.get("entry_score")
            or (payload.get("quality_dimensions") or {}).get("entry_quality")
            or payload.get("entry_quality")
            or payload.get("candidate_final_score", payload.get("quality"))
        ),
        "durability_score": payload.get("durability_score") or (payload.get("quality_dimensions") or {}).get("durability_quality"),
        "execution_stage": payload.get("entry_stage", payload.get("execution_stage")),
        "execution_source": payload.get("execution_source"),
        "trigger_ready": bool(payload.get("trigger_ready")),
        "confirmation_pending": bool(payload.get("confirmation_pending")),
        "thesis_key": payload.get("thesis_key"),
        "entry_supported": entry_supported,
        "execution_path": execution_path,
        "blocking_reason": blocking_reason,
        "short_reversal": bool(payload.get("short_reversal") or (payload.get("short_reversal_profile") or {}).get("active")),
        "funnel": dict(payload.get("funnel") or {}) or {
            key: bool(funnel.get(key))
            for key in (
                "plan_execution_ready", "philosophy_accepts",
                "executive_pre_conflict_eligible",
            )
            if key in funnel
        },
    }
    return {key: value for key, value in compact.items() if value not in (None, "", {}, [])}


def prepare_signal_payload_for_journal(payload: dict[str, Any]) -> dict[str, Any]:
    """Compatibility alias retained for older call sites."""
    return compact_signal_for_journal(payload)


def compact_trade_for_journal(payload: dict[str, Any]) -> dict[str, Any]:
    """Compact a closed trade while preserving outcome learning and joins."""
    if not isinstance(payload, dict):
        return {}
    pnl = payload.get("pnl")
    if pnl is None:
        pnl = payload.get("realized_return_pct", payload.get("result_pct"))
    pnl_r = payload.get("pnl_r", payload.get("result_r"))
    result = payload.get("result") or payload.get("close_action") or payload.get("action") or payload.get("outcome_status")
    compact = {
        "id": payload.get("id"),
        "signal_id": payload.get("signal_id", payload.get("primary_signal_id")),
        "time": payload.get("time", payload.get("opened_at")),
        "closed_at": payload.get("closed_at"),
        "side": payload.get("side"),
        "setup_family": payload.get("setup_family"),
        "setup_type": payload.get("setup_type"),
        "score": payload.get("score", payload.get("quality")),
        "entry_score": payload.get("entry_score", payload.get("entry_quality", payload.get("quality"))),
        "execution_stage": payload.get("execution_stage", payload.get("entry_stage")),
        "execution_source": payload.get("execution_source"),
        "result": result,
        "pnl": pnl,
        "pnl_r": pnl_r,
        "close_reason": payload.get("close_reason", payload.get("close_action", payload.get("action"))),
        "mfe": payload.get("mfe", payload.get("mfe_pct")),
        "risk_pct": payload.get("risk_pct", payload.get("position_risk_pct")),
        "regime": payload.get("regime", payload.get("opened_regime")),
        "ml_eligible": payload.get("ml_eligible", True),
    }
    return {key: value for key, value in compact.items() if value not in (None, "", {}, [])}


def migrate_journal_to_v2(journal: dict[str, Any]) -> dict[str, Any]:
    """One-time in-memory migration of legacy journals to schema version 2."""
    if not isinstance(journal, dict):
        journal = {}
    legacy_training_source = list(journal.get("training_signals") or []) + list(journal.get("signals") or [])
    dedup_training: dict[str, dict[str, Any]] = {}
    for item in legacy_training_source:
        lean = lean_training_signal(item) if isinstance(item, dict) else {}
        if lean:
            dedup_training[str(lean["id"])] = lean
    journal["training_signals"] = list(dedup_training.values())[-MAX_JOURNAL:]
    journal["signals"] = [
        compact for item in list(journal.get("signals") or [])
        if isinstance(item, dict)
        for compact in [compact_signal_for_journal(item)] if compact
    ][-MAX_JOURNAL:]
    journal["trades"] = [
        compact for item in list(journal.get("trades") or [])
        if isinstance(item, dict)
        for compact in [compact_trade_for_journal(item)] if compact
    ][-MAX_JOURNAL:]
    journal["signal_events"] = [item for item in list(journal.get("signal_events") or []) if isinstance(item, dict)][-MAX_JOURNAL:]
    journal["executive_divergences"] = [item for item in list(journal.get("executive_divergences") or []) if isinstance(item, dict)][-EXECUTIVE_DIVERGENCE_JOURNAL_LIMIT:]
    journal["rejected_hypothesis_shadows"] = [item for item in list(journal.get("rejected_hypothesis_shadows") or []) if isinstance(item, dict)][-REJECTED_HYPOTHESIS_SHADOW_LIMIT:]
    journal["preconfirmation_events"] = _retain_preconfirmation_events(
        list(journal.get("preconfirmation_events") or []), PRECONFIRM_EMBEDDED_JOURNAL_LIMIT
    )
    journal["journal_version"] = JOURNAL_VERSION
    journal["migration"] = {
        "from_version": int(journal.get("journal_version_before_migration", 1) or 1),
        "to_version": JOURNAL_VERSION,
        "mode": "AUTO_COMPACT_ON_LOAD",
        "completed_at": iso_now(),
    }
    return journal


def load_journal() -> dict[str, Any]:
    journal = load_json(JOURNAL_FILE, {})
    old_version = int(journal.get("journal_version", 1) or 1)
    if old_version < JOURNAL_VERSION:
        journal["journal_version_before_migration"] = old_version
        journal = migrate_journal_to_v2(journal)
        journal.pop("journal_version_before_migration", None)
        atomic_json_write(JOURNAL_FILE, journal)
    journal.setdefault("signals", [])
    journal.setdefault("training_signals", [])
    journal.setdefault("signal_events", [])
    journal.setdefault("trades", [])
    journal.setdefault("relaxed_continuation_experiments", [])
    journal.setdefault("executive_divergences", [])
    journal.setdefault("rejected_hypothesis_shadows", [])
    journal.setdefault("preconfirmation_events", [])
    journal.setdefault("preconfirmation_model_status", {})
    journal["training_signals"] = [
        lean for item in list(journal.get("training_signals") or [])
        if isinstance(item, dict)
        for lean in [lean_training_signal(item)] if lean
    ]
    journal["signals"] = [
        compact for item in list(journal.get("signals") or [])
        if isinstance(item, dict)
        for compact in [compact_signal_for_journal(item)] if compact
    ]
    journal["trades"] = [
        compact for item in list(journal.get("trades") or [])
        if isinstance(item, dict)
        for compact in [compact_trade_for_journal(item)] if compact
    ]
    journal["journal_version"] = JOURNAL_VERSION
    journal["version"] = BOT_VERSION
    journal["architecture_version"] = ARCHITECTURE_VERSION
    if "analytics" not in journal:
        journal["analytics"] = {"closed_trades": 0, "wins": 0, "losses": 0, "win_rate": 0.0, "net_r": 0.0, "expectancy_r": 0.0, "by_family": {}}
    return journal


def deduplicate_closed_trades(trades: list[Any]) -> list[dict[str, Any]]:
    """Не даємо ML двічі вчитись на одній і тій самій закритій угоді.
    Ключ максимально консервативний: trade id + signal_id + close_action; якщо id
    порожній, лишаємо запис, бо це старий/пошкоджений журнал і краще не робити
    вигляд, що ми всевидяче божество з JSON-скальпелем."""
    cleaned: list[dict[str, Any]] = []
    seen: set[tuple[str, str, str]] = set()
    for item in trades or []:
        if not isinstance(item, dict):
            continue
        tid = str(item.get("id") or "").strip()
        sid = str(item.get("signal_id") or "").strip()
        action = str(item.get("close_action") or item.get("action") or "").strip()
        if tid:
            key = (tid, sid, action)
            if key in seen:
                continue
            seen.add(key)
        cleaned.append(item)
    return cleaned



def _retain_signal_records(records: list[Any], protected_signal_ids: set[str], cap: int) -> list[dict[str, Any]]:
    """Retain records referenced by trades/open positions before applying FIFO.

    The cap applies to the final list when possible. If protected records alone
    exceed the cap, they are all kept because referential integrity beats a neat
    round number in an environment where silent ML label loss is rather expensive.
    """
    cleaned = [r for r in records or [] if isinstance(r, dict) and r.get("id")]
    protected = [r for r in cleaned if str(r.get("id") or "") in protected_signal_ids]
    protected_keys = {str(r.get("id") or "") for r in protected}
    unprotected = [r for r in cleaned if str(r.get("id") or "") not in protected_keys]
    room = max(0, int(cap) - len(protected))
    kept = protected + (unprotected[-room:] if room else [])
    # Preserve chronological/original order after combining the two groups.
    order = {id(record): idx for idx, record in enumerate(cleaned)}
    return sorted(kept, key=lambda record: order.get(id(record), 0))


def _retain_signal_events(events: list[Any], protected_signal_ids: set[str], cap: int) -> list[dict[str, Any]]:
    cleaned = [e for e in events or [] if isinstance(e, dict)]
    protected = [e for e in cleaned if str(e.get("signal_id") or "") in protected_signal_ids]
    protected_obj_ids = {id(e) for e in protected}
    unprotected = [e for e in cleaned if id(e) not in protected_obj_ids]
    room = max(0, int(cap) - len(protected))
    kept = protected + (unprotected[-room:] if room else [])
    order = {id(record): idx for idx, record in enumerate(cleaned)}
    return sorted(kept, key=lambda record: order.get(id(record), 0))

def save_journal(journal: dict[str, Any]) -> None:
    journal["updated_at"] = iso_now()
    journal["journal_version"] = JOURNAL_VERSION

    journal["trades"] = deduplicate_closed_trades([
        compact for item in list(journal.get("trades") or [])
        if isinstance(item, dict)
        for compact in [compact_trade_for_journal(item)] if compact
    ])[-MAX_JOURNAL:]
    active_protected = {str(x) for x in (journal.get("protected_signal_ids") or []) if str(x).strip()}
    trade_protected = {
        str(t.get("signal_id") or "") for t in journal.get("trades", [])
        if isinstance(t, dict) and str(t.get("signal_id") or "").strip()
    }
    protected_signal_ids = active_protected | trade_protected

    journal["signals"] = _retain_signal_records(
        [
            compact for item in list(journal.get("signals") or [])
            if isinstance(item, dict)
            for compact in [compact_signal_for_journal(item)] if compact
        ],
        protected_signal_ids,
        MAX_JOURNAL,
    )
    journal["training_signals"] = _retain_signal_records(
        [
            lean for item in list(journal.get("training_signals") or [])
            if isinstance(item, dict)
            for lean in [lean_training_signal(item)] if lean
        ],
        protected_signal_ids,
        MAX_JOURNAL,
    )
    journal["signal_events"] = _retain_signal_events(
        list(journal.get("signal_events") or []), protected_signal_ids, MAX_JOURNAL
    )
    journal["executive_divergences"] = [
        item for item in list(journal.get("executive_divergences") or []) if isinstance(item, dict)
    ][-EXECUTIVE_DIVERGENCE_JOURNAL_LIMIT:]
    journal["rejected_hypothesis_shadows"] = [
        item for item in list(journal.get("rejected_hypothesis_shadows") or []) if isinstance(item, dict)
    ][-REJECTED_HYPOTHESIS_SHADOW_LIMIT:]
    journal["relaxed_continuation_experiments"] = [
        item for item in list(journal.get("relaxed_continuation_experiments") or []) if isinstance(item, dict)
    ][-RELAXED_CONTINUATION_SHADOW_HISTORY_LIMIT:]
    journal["preconfirmation_events"] = _retain_preconfirmation_events(
        list(journal.get("preconfirmation_events") or []), PRECONFIRM_EMBEDDED_JOURNAL_LIMIT
    )
    journal["retention_audit"] = {
        "journal_version": JOURNAL_VERSION,
        "signals": len(journal["signals"]),
        "training_signals": len(journal["training_signals"]),
        "trades": len(journal["trades"]),
        "preconfirmation_events": len(journal["preconfirmation_events"]),
        "limits": {
            "signals": MAX_JOURNAL,
            "training_signals": MAX_JOURNAL,
            "executive_divergences": EXECUTIVE_DIVERGENCE_JOURNAL_LIMIT,
            "rejected_hypothesis_shadows": REJECTED_HYPOTHESIS_SHADOW_LIMIT,
            "preconfirmation_events": PRECONFIRM_EMBEDDED_JOURNAL_LIMIT,
        },
    }
    journal["analytics"] = compute_analytics(journal)
    journal["setup_statistics"] = compute_setup_statistics(journal)
    journal["calendar_statistics"] = compute_calendar_statistics(journal)
    journal["learning_status"] = compute_learning_status(journal)
    atomic_json_write(JOURNAL_FILE, journal)


def append_history(state: dict[str, Any], item: dict[str, Any]) -> None:
    payload = dict(item)
    payload.setdefault("time", iso_now())
    state.setdefault("history", []).append(payload)
    state["history"] = state["history"][-MAX_HISTORY:]


def active_trade_from_state(state: dict[str, Any]) -> Optional[ActiveTrade]:
    raw = state.get("active_trade")
    if not isinstance(raw, dict):
        return None
    try:
        fields = ActiveTrade.__dataclass_fields__
        clean = {k: raw.get(k) for k in fields if k in raw}
        clean.setdefault("thesis_key", str(raw.get("thesis_key", "")))
        clean.setdefault("thesis", str(raw.get("thesis", "")))
        clean.setdefault("entry_integrity_score", int(raw.get("entry_integrity_score", 100) or 100))
        clean.setdefault("entry_fail_streak", int(raw.get("entry_fail_streak", 0) or 0))
        clean.setdefault("mfe_giveback_streak", int(raw.get("mfe_giveback_streak", 0) or 0))
        clean.setdefault("mfe_giveback_last_state", str(raw.get("mfe_giveback_last_state", "OK")))
        clean.setdefault("trigger_level", float(raw.get("trigger_level", 0) or 0))
        clean.setdefault("opened_regime", str(raw.get("opened_regime", "")))
        clean.setdefault("tp1_stop_locked", bool(raw.get("tp1_stop_locked", False)))
        clean.setdefault("tp2_stop_locked", bool(raw.get("tp2_stop_locked", False)))
        clean.setdefault("tp1_locked_stop", float(raw.get("tp1_locked_stop", 0) or 0))
        clean.setdefault("tp2_locked_stop", float(raw.get("tp2_locked_stop", 0) or 0))
        return ActiveTrade(**clean)
    except Exception as exc:
        print(f"[WARN] ActiveTrade migration failed: {exc}")
        return None


def store_active_trade(state: dict[str, Any], trade: Optional[ActiveTrade]) -> None:
    state["active_trade"] = asdict(trade) if trade else None


def opportunity_from_state(state: dict[str, Any]) -> Optional[Opportunity]:
    raw = state.get("opportunity")
    if not isinstance(raw, dict):
        return None
    try:
        return Opportunity(**{k: raw.get(k) for k in Opportunity.__dataclass_fields__ if k in raw})
    except Exception:
        return None


def store_opportunity(state: dict[str, Any], opp: Optional[Opportunity]) -> None:
    state["opportunity"] = asdict(opp) if opp else None


